// Helper functions
export function getArticleById(id, lang) {
  return allArticles[lang]?.find((a) => a.id === Number(id));
}

export function getFeaturedArticle(lang) {
  return allArticles[lang]?.find((a) => a.featured) || allArticles[lang]?.[0];
}

export function getLatestArticles(lang, limit = 6) {
  return allArticles[lang]?.filter((a) => !a.featured).slice(0, limit) || [];
}

export function getArticlesByCategory(lang, category) {
  return allArticles[lang]?.filter((a) => a.category === category) || [];
}

export function getMostReadArticles(lang) {
  const ids = [10, 11, 12, 13, 14];
  return ids.map((id) => allArticles[lang]?.find((a) => a.id === id)).filter(Boolean);
}

export function getCategorySections(lang) {
  return {
    sports: getArticlesByCategory(lang, 'sports').slice(0, 3),
    tech: getArticlesByCategory(lang, 'tech').slice(0, 3),
    lifestyle: getArticlesByCategory(lang, 'lifestyle').slice(0, 3),
  };
}
